INSERT INTO `_meta_tables` (`table_name`, `description_vi`, `description_en`, `business_context`, `row_count_estimate`) VALUES
  ('_meta_columns', 'Mô tả từng cột trong database', 'Column descriptions metadata', 'AI engine dùng để hiểu ý nghĩa từng cột, đơn vị', NULL),
  ('_meta_glossary', 'Thuật ngữ ngành Nông nghiệp & Chăn nuôi VN-EN', 'Industry glossary Vietnamese-English', 'AI engine dùng để hiểu thuật ngữ chuyên ngành', NULL),
  ('_meta_kpi', 'Định nghĩa KPI và công thức SQL', 'KPI definitions with SQL formulas', 'AI engine dùng để tính KPI chính xác', NULL),
  ('_meta_tables', 'Mô tả từng bảng trong database', 'Table descriptions metadata', 'AI engine dùng để hiểu cấu trúc database', 23),
  ('bill_of_materials', 'Công thức sản phẩm TACN: lượng NVL cần cho mỗi tấn thành phẩm', 'Product bill of materials', 'Dùng kết hợp với material_purchases để tính impact giá NVL lên COGS', 748),
  ('business_segments', 'Các mảng kinh doanh cốt lõi của Nova Consumer: Thuốc thú y & Vaccine, Thức ăn chăn nuôi, Trang trại', 'Core business segments of Nova Consumer Group', 'Dùng khi cần phân tích theo mảng kinh doanh, so sánh hiệu quả giữa các mảng', 3),
  ('customers', 'Khách hàng/đại lý phân theo segment, kênh, vùng miền, tier (A/B/C)', 'Customers and dealers', 'Dùng khi phân tích khách hàng, top customers, retention', 200),
  ('distribution_channels', 'Kênh phân phối: đại lý, trang trại lớn, BV thú y, xuất khẩu, nội bộ, online', 'Distribution channels', 'Dùng khi phân tích doanh thu theo kênh, chiến lược phân phối', 10),
  ('factories', 'Hệ thống nhà máy sản xuất: 3 NM TACN (Long An, Đồng Nai, Hưng Yên) + 2 NM Thuốc thú y', 'Manufacturing facilities for feed and veterinary products', 'Dùng khi phân tích sản xuất, công suất, chi phí SX', 5),
  ('farm_operations', 'Vận hành trang trại hàng tháng: đàn vật nuôi, chi phí, doanh thu', 'Monthly farm operations', 'Dùng khi phân tích chi phí chăn nuôi, hiệu quả trang trại', 126),
  ('farms', 'Hệ thống trang trại chăn nuôi: Hàm Tân (heo), Đắk Nông (heo+gà), Bình Dương (bò)', 'Livestock farms', 'Dùng khi phân tích vận hành trang trại, đàn vật nuôi', 3),
  ('logistics_costs', 'Chi phí vận chuyển giữa nhà máy và vùng tiêu thụ', 'Logistics cost matrix', 'Dùng cho S4 follow-up: tính chi phí logistics khi chuyển sản lượng giữa NM', 21),
  ('material_purchases', 'Lịch sử mua NVL chi tiết: ngày mua, giá, khối lượng, nhà cung cấp, nhà máy', 'Raw material purchase history', 'Bảng chính cho S3: tracking giá NVL theo thời gian, so sánh giữa nhà máy', 5292),
  ('product_categories', 'Phân cấp danh mục sản phẩm 3 level: Group → Category → Sub-category', 'Product category hierarchy', 'Dùng khi phân tích theo nhóm sản phẩm, drill-down từ mảng KD xuống danh mục', 26),
  ('production_monthly', 'Chi phí và sản lượng sản xuất theo nhà máy, hàng tháng. Breakdown: NVL, nhân công, khấu hao, overhead', 'Monthly production data by factory', 'Bảng chính cho S2+S4: chi phí SX/tấn, utilization rate. Có generated columns', 90),
  ('production_orders', 'Đơn hàng sản xuất: tracking sản lượng theo khách hàng, tiến độ', 'Production orders', 'Dùng khi phân tích demand, mất khách (S2 anomaly)', 2987),
  ('products', 'Danh mục SKU sản phẩm toàn tập đoàn: thuốc thú y, TACN, sản phẩm trang trại', 'Product SKU catalog', 'Dùng khi phân tích doanh thu/margin theo sản phẩm, Pareto analysis', 148),
  ('raw_materials', 'Danh mục nguyên vật liệu: NVL TACN (ngô, đậu tương, cám...) + NVL thuốc thú y', 'Raw materials catalog', 'Dùng khi phân tích giá NVL, biến động chi phí, COGS breakdown', 15),
  ('regions', 'Hệ thống vùng miền và tỉnh thành Việt Nam, 7 vùng kinh tế + tỉnh trọng điểm', 'Vietnamese economic regions and provinces', 'Dùng khi phân tích geographic, phân bổ thị trường, logistics', 25),
  ('sales_transactions', 'Giao dịch bán hàng chi tiết: sản phẩm, khách hàng, kênh, nhà máy, vùng miền', 'Detailed sales transactions', 'Bảng lớn nhất — phân tích doanh thu đa chiều: sản phẩm × kênh × vùng × thời gian', 38141),
  ('segment_financials', 'Báo cáo tài chính P&L theo mảng kinh doanh, hàng tháng. 18 tháng (07/2024-12/2025)', 'Monthly P&L by business segment', 'Bảng chính cho S1: phân tích margin, DT, COGS theo mảng. Có generated columns gross_profit, gross_margin_pct', 54),
  ('subsidiaries', 'Danh sách công ty con và liên kết thuộc Nova Consumer Group', 'Subsidiaries and affiliated companies', 'Dùng khi cần truy xuất thông tin công ty con, phân tích theo đơn vị pháp lý', 8),
  ('suppliers', 'Nhà cung cấp NVL trong và ngoài nước: Cargill, Bunge, HTX nội địa...', 'Raw material suppliers', 'Dùng khi phân tích sourcing, so sánh giá giữa nhà cung cấp', 30);
