INSERT INTO `_meta_kpi` (`kpi_name`, `kpi_name_en`, `formula_sql`, `description_vi`, `related_questions`, `source_tables`) VALUES
  ('Biên lợi nhuận gộp theo mảng', 'Gross Margin by Segment', 'SELECT bs.segment_name, sf.`year_month`, sf.total_revenue, sf.total_cogs, sf.gross_profit, sf.gross_margin_pct FROM segment_financials sf JOIN business_segments bs ON sf.segment_id = bs.segment_id WHERE sf.`year_month` = ? ORDER BY sf.gross_margin_pct DESC', 'Tính biên lợi nhuận gộp (%) = (Doanh thu - Giá vốn) / Doanh thu × 100. So sánh giữa 3 mảng KD để xác định mảng nào hiệu quả nhất.', 'Câu 1: Biên LN gộp từng mảng quý gần nhất so cùng kỳ?', 'segment_financials, business_segments'),
  ('Chi phí sản xuất trên mỗi tấn', 'Production Cost per Ton', 'SELECT f.factory_name, pm.`year_month`, pm.actual_output_tons, pm.raw_material_cost, pm.labor_cost, pm.depreciation, pm.overhead, pm.total_production_cost, pm.cost_per_ton FROM production_monthly pm JOIN factories f ON pm.factory_id = f.factory_id WHERE pm.`year_month` = ? AND f.factory_type = \'Thức ăn chăn nuôi\' ORDER BY pm.cost_per_ton DESC', 'Chi phí SX/tấn = Tổng chi phí SX / Sản lượng. Breakdown: NVL + Nhân công + Khấu hao + Overhead. So sánh 3 nhà máy TACN.', 'Câu 2: Chi phí SX/tấn tại 3 NM — NM nào chi phí cao bất thường?', 'production_monthly, factories'),
  ('Hiệu suất sử dụng công suất', 'Capacity Utilization Rate', 'SELECT f.factory_name, pm.`year_month`, pm.actual_output_tons, pm.max_capacity_tons, pm.utilization_pct, (pm.max_capacity_tons - pm.actual_output_tons) as spare_capacity FROM production_monthly pm JOIN factories f ON pm.factory_id = f.factory_id WHERE pm.`year_month` = ? ORDER BY pm.utilization_pct', 'Utilization = Sản lượng thực tế / Công suất thiết kế × 100%. Dùng để đánh giá dư địa tăng sản lượng.', 'Câu 4: So sánh hiệu suất 3 NM TACN — dư địa tăng sản lượng?', 'production_monthly, factories'),
  ('Giá NVL trung bình theo tháng', 'Average Material Price by Month', 'SELECT rm.material_name, DATE_FORMAT(mp.purchase_date, \'%Y-%m\') as month, AVG(mp.unit_price) as avg_price, SUM(mp.quantity_tons) as total_qty FROM material_purchases mp JOIN raw_materials rm ON mp.material_id = rm.material_id WHERE mp.purchase_date BETWEEN ? AND ? GROUP BY rm.material_name, month ORDER BY rm.material_name, month', 'Giá mua trung bình NVL theo tháng, tracking biến động giá. Kết hợp với cogs_share_pct để đánh giá impact lên giá vốn.', 'Câu 3: NVL nào gây áp lực lên giá vốn? Biến động 6 tháng qua?', 'material_purchases, raw_materials'),
  ('Doanh thu theo kênh phân phối', 'Revenue by Distribution Channel', 'SELECT dc.channel_name, bs.segment_name, SUM(st.total_revenue) as total_rev, COUNT(*) as txn_count FROM sales_transactions st JOIN distribution_channels dc ON st.channel_id = dc.channel_id JOIN business_segments bs ON st.segment_id = bs.segment_id WHERE st.sale_date BETWEEN ? AND ? GROUP BY dc.channel_name, bs.segment_name ORDER BY total_rev DESC', 'Phân tích doanh thu theo kênh phân phối và mảng KD. Xác định kênh chính, kênh tăng trưởng.', 'Câu 5: 3 đòn bẩy cải thiện margin (phân tích kênh thuốc thú y)', 'sales_transactions, distribution_channels, business_segments'),
  ('Doanh thu theo vùng miền', 'Revenue by Region', 'SELECT r.region_name, SUM(st.total_revenue) as total_rev, COUNT(*) as txn_count FROM sales_transactions st JOIN regions r ON st.region_id = r.region_id WHERE st.sale_date BETWEEN ? AND ? GROUP BY r.region_name ORDER BY total_rev DESC', 'Phân bổ doanh thu theo địa lý — xác định vùng trọng điểm, vùng yếu.', NULL, 'sales_transactions, regions'),
  ('Top sản phẩm theo doanh thu', 'Top Products by Revenue', 'SELECT p.product_name, p.brand, SUM(st.total_revenue) as total_rev, SUM(st.quantity) as total_qty, AVG(st.unit_price) as avg_price FROM sales_transactions st JOIN products p ON st.product_id = p.product_id WHERE st.sale_date BETWEEN ? AND ? GROUP BY p.product_name, p.brand ORDER BY total_rev DESC LIMIT 20', 'Pareto analysis: top 20% SKU chiếm 80% doanh thu. Dùng popularity_weight để verify.', NULL, 'sales_transactions, products'),
  ('Impact giá NVL lên margin', 'Material Price Impact on Margin', 'SELECT rm.material_name, rm.cogs_share_pct, AVG(CASE WHEN mp.purchase_date >= DATE_SUB(?, INTERVAL 3 MONTH) THEN mp.unit_price END) as recent_price, AVG(CASE WHEN mp.purchase_date < DATE_SUB(?, INTERVAL 3 MONTH) AND mp.purchase_date >= DATE_SUB(?, INTERVAL 6 MONTH) THEN mp.unit_price END) as prev_price FROM material_purchases mp JOIN raw_materials rm ON mp.material_id = rm.material_id GROUP BY rm.material_name, rm.cogs_share_pct ORDER BY rm.cogs_share_pct DESC', 'Tính mỗi 1% tăng giá NVL → giảm bao nhiêu pp margin. Impact = cogs_share × price_change / revenue.', 'Câu 3 follow-up: mỗi 1% tăng giá ngô → giảm ~0.35pp margin TACN', 'material_purchases, raw_materials'),
  ('Chi phí chăn nuôi bình quân đầu con', 'Farm Cost per Head', 'SELECT fm.farm_name, fo.animal_type, fo.`year_month`, fo.total_cost, (fo.opening_stock + fo.closing_stock)/2 as avg_stock, fo.total_cost / ((fo.opening_stock + fo.closing_stock)/2) as cost_per_head FROM farm_operations fo JOIN farms fm ON fo.farm_id = fm.farm_id WHERE fo.`year_month` = ? ORDER BY cost_per_head DESC', 'Tổng chi phí / Số đầu con bình quân. Breakdown: TACN, thú y, nhân công, khác.', NULL, 'farm_operations, farms'),
  ('Tăng trưởng doanh thu YoY', 'YoY Revenue Growth', 'SELECT sf_cur.segment_id, bs.segment_name, sf_cur.`year_month` as current_month, sf_cur.total_revenue as current_rev, sf_prev.total_revenue as prev_year_rev, ROUND((sf_cur.total_revenue - sf_prev.total_revenue) / sf_prev.total_revenue * 100, 2) as yoy_growth_pct FROM segment_financials sf_cur JOIN segment_financials sf_prev ON sf_cur.segment_id = sf_prev.segment_id AND sf_prev.`year_month` = DATE_SUB(sf_cur.`year_month`, INTERVAL 12 MONTH) JOIN business_segments bs ON sf_cur.segment_id = bs.segment_id WHERE sf_cur.`year_month` = ? ORDER BY yoy_growth_pct DESC', 'So sánh doanh thu tháng hiện tại với cùng kỳ năm trước. Tính % tăng trưởng.', 'Câu 1: So cùng kỳ năm ngoái', 'segment_financials, business_segments'),
  ('Giá NVL theo nhà máy', 'Material Price Comparison by Factory', 'SELECT f.factory_name, rm.material_name, AVG(mp.unit_price) as avg_price FROM material_purchases mp JOIN factories f ON mp.factory_id = f.factory_id JOIN raw_materials rm ON mp.material_id = rm.material_id WHERE mp.purchase_date BETWEEN ? AND ? AND rm.material_code = \'NVL_NGO\' GROUP BY f.factory_name, rm.material_name ORDER BY avg_price', 'So sánh giá nhập NVL giữa các nhà máy — phát hiện chênh lệch sourcing. VD: Hưng Yên rẻ hơn 5% nhờ supplier nội địa.', 'Câu 3 follow-up: So sánh giá nhập ngô giữa 3 NM', 'material_purchases, factories, raw_materials');
INSERT INTO `_meta_glossary` (`term_vi`, `term_en`, `abbreviation`, `definition`, `related_table`, `related_column`) VALUES
  ('Thức ăn chăn nuôi', 'Animal Feed', 'TACN', 'Sản phẩm công nghiệp dùng để nuôi gia súc, gia cầm, thủy sản. Gồm thức ăn hỗn hợp hoàn chỉnh, thức ăn đậm đặc, premix.', 'products', 'segment_id'),
  ('Giá vốn hàng bán', 'Cost of Goods Sold', 'COGS', 'Tổng chi phí trực tiếp sản xuất hàng hóa đã bán: NVL, nhân công trực tiếp, khấu hao, overhead SX.', 'segment_financials', 'total_cogs'),
  ('Biên lợi nhuận gộp', 'Gross Margin', 'GPM', 'Tỷ lệ phần trăm lợi nhuận gộp trên doanh thu. Công thức: (DT - COGS) / DT × 100%.', 'segment_financials', 'gross_margin_pct'),
  ('Doanh thu thuần', 'Net Revenue', NULL, 'Doanh thu sau khi trừ chiết khấu, giảm giá, hàng trả lại.', 'segment_financials', 'total_revenue'),
  ('Dịch tả lợn châu Phi', 'African Swine Fever', 'ASF', 'Bệnh virus gây chết 100% heo nhiễm. Không có vaccine. Ảnh hưởng lớn đến quy mô đàn heo VN.', NULL, NULL),
  ('Lở mồm long móng', 'Foot-and-Mouth Disease', 'FMD', 'Bệnh virus cực kỳ lây lan ở động vật guốc chẵn. Vaccine FMD bắt buộc tiêm phòng tại VN.', 'products', NULL),
  ('WHO-GMP', 'WHO Good Manufacturing Practice', 'WHO-GMP', 'Tiêu chuẩn sản xuất thuốc của WHO. Nova Consumer có 2 nhà máy đạt chuẩn này.', 'factories', 'certification'),
  ('GLOBALG.A.P', 'Global Good Agricultural Practices', 'GAP', 'Tiêu chuẩn thực hành nông nghiệp tốt toàn cầu. Áp dụng cho trang trại chăn nuôi.', 'farms', 'certification'),
  ('Hiệu suất sử dụng công suất', 'Capacity Utilization Rate', NULL, 'Tỷ lệ sản lượng thực tế / công suất thiết kế. Lý tưởng: 75-85%. Dưới 60%: đốt tiền.', 'production_monthly', 'utilization_pct'),
  ('Công thức sản phẩm', 'Bill of Materials', 'BOM', 'Danh sách NVL và tỷ lệ phối trộn để sản xuất 1 tấn thức ăn chăn nuôi.', 'bill_of_materials', NULL),
  ('Premix', 'Premix', NULL, 'Hỗn hợp vitamin, khoáng chất, axit amin được phối trộn sẵn, bổ sung vào TACN. Chiếm ~5% COGS.', 'raw_materials', NULL),
  ('Khô đậu tương', 'Soybean Meal', 'SBM', 'Nguồn đạm thực vật chính trong TACN. Nhập khẩu từ Argentina, Brazil. Chiếm ~25% COGS.', 'raw_materials', NULL),
  ('Ngô hạt', 'Corn / Maize', NULL, 'Nguồn năng lượng chính trong TACN. Nhập khẩu ~60-70%. Chiếm ~35% COGS — biến động giá ảnh hưởng lớn nhất.', 'raw_materials', NULL),
  ('DDGS', 'Distillers Dried Grains with Solubles', 'DDGS', 'Phụ phẩm từ sản xuất ethanol từ ngô. Nguồn đạm và năng lượng bổ sung. Nhập từ Mỹ.', 'raw_materials', NULL),
  ('Cám gạo', 'Rice Bran', NULL, 'Phụ phẩm xay xát gạo, nguồn năng lượng nội địa. Giá ổn định, ít biến động.', 'raw_materials', NULL),
  ('Heo nái', 'Sow / Breeding Pig', NULL, 'Heo cái giống dùng để sinh sản. Quy mô đàn nái quyết định sản lượng heo thịt.', 'farm_operations', 'animal_type'),
  ('Heo thịt', 'Fattening Pig / Market Hog', NULL, 'Heo nuôi lấy thịt, xuất chuồng ~100-120kg sau 5-6 tháng nuôi.', 'farm_operations', 'animal_type'),
  ('Gà lông trắng', 'White Broiler', NULL, 'Giống gà công nghiệp (Cobb, Ross) nuôi 35-42 ngày, trọng lượng 2-3kg. Sản lượng lớn.', 'products', NULL),
  ('Gà lông màu', 'Color Broiler / Free-range Chicken', NULL, 'Giống gà bản địa/lai, nuôi 60-90 ngày. Giá cao hơn gà lông trắng ~20-30%.', 'products', NULL),
  ('Bò sữa', 'Dairy Cattle', NULL, 'Bò giống Holstein Friesian, sản lượng 15-25 lít sữa/ngày. TACN bò sữa yêu cầu dinh dưỡng cao.', 'farm_operations', 'animal_type'),
  ('Bò thịt', 'Beef Cattle', NULL, 'Bò nuôi lấy thịt, trọng lượng xuất chuồng 350-450kg. Giá bò hơi ~85-95K đ/kg.', 'farm_operations', 'animal_type'),
  ('Vaccine thú y', 'Veterinary Vaccine', NULL, 'Chế phẩm sinh học dùng phòng bệnh cho vật nuôi. Margin cao (~55-60% với vaccine nhập khẩu).', 'products', NULL),
  ('Kháng sinh thú y', 'Veterinary Antibiotic', NULL, 'Thuốc kháng khuẩn dùng điều trị bệnh nhiễm khuẩn ở vật nuôi. Xu hướng giảm sử dụng để đảm bảo ATTP.', 'products', NULL),
  ('Chi phí cố định', 'Fixed Cost', NULL, 'Chi phí không thay đổi theo sản lượng: khấu hao, lương cố định, bảo hiểm. Khi utilization giảm → chi phí cố định/tấn tăng.', 'production_monthly', NULL),
  ('Chi phí biến đổi', 'Variable Cost', NULL, 'Chi phí thay đổi tỷ lệ thuận với sản lượng: NVL, nhân công thời vụ, điện SX.', 'production_monthly', NULL),
  ('Khấu hao', 'Depreciation', NULL, 'Phân bổ giá trị tài sản cố định (nhà máy, máy móc) theo thời gian sử dụng. Chi phí cố định.', 'production_monthly', 'depreciation'),
  ('Công suất thiết kế', 'Design Capacity', NULL, 'Sản lượng tối đa nhà máy có thể sản xuất trong điều kiện vận hành tiêu chuẩn.', 'factories', 'max_capacity_tons_month'),
  ('Đại lý cấp 1', 'Tier 1 Dealer', NULL, 'Khách hàng lớn mua trực tiếp từ công ty, phân phối lại cho đại lý cấp 2 và nông hộ.', 'customers', 'customer_type'),
  ('Trang trại lớn', 'Large Farm / Integrator', NULL, 'Trang trại quy mô công nghiệp (>1000 con heo, >10000 con gà). Mua TACN số lượng lớn.', 'customers', 'customer_type'),
  ('Xuất khẩu', 'Export', NULL, 'Thị trường ngoài VN: Campuchia, Lào, Myanmar, Philippines. TACN xuất khẩu tăng mạnh ~35% YoY.', 'customers', 'customer_type'),
  ('Mô hình 3F', 'Feed-Farm-Food Model', '3F', 'Chuỗi giá trị khép kín: sản xuất TACN → chăn nuôi → chế biến thực phẩm. Giúp kiểm soát chất lượng và margin.', NULL, NULL),
  ('FCR', 'Feed Conversion Ratio', 'FCR', 'Tỷ lệ chuyển đổi thức ăn: số kg TACN cần để tăng 1kg thể trọng. Heo: ~2.5-3.0, Gà lông trắng: ~1.5-1.8.', NULL, NULL),
  ('Giá heo hơi', 'Live Pig Price', NULL, 'Giá bán heo sống tại chuồng, chưa giết mổ. Năm 2024: 60-67K đ/kg. Quyết định lợi nhuận trang trại.', 'farm_operations', NULL);
